CODE_EXAMPLE:
/**
 * Formats a date in RFC-1123 format (e.g., Tue, 3 Jun 2008).
 * @param date the date to format, must not be null
 * @return RFC-1123 formatted string
 */
public String formatDate(Date date) {
    // SimpleDateFormat is NOT thread-safe
    return new SimpleDateFormat("EEE, d MMM yyyy").format(date);
}

// TODO: replace SimpleDateFormat with DateTimeFormatter once on Java 8+

UNIT_TEST_EXAMPLE:
@Test
public void formatDate_producesRfc1123Format() {
    DateFormatter formatter = new DateFormatter();
    Calendar cal = Calendar.getInstance();
    cal.set(2008, Calendar.JUNE, 3);
    String result = formatter.formatDate(cal.getTime());
    assertTrue(result.matches("\\w+, \\d+ \\w+ \\d{4}"));
}
